class StructuredDiagnosticClient final: public slang::DiagnosticClient {
  public:
    void report(const slang::ReportedDiagnostic& diagnostic) override {
      SNLSVDiagnostic result;
      result.severity = getSeverityString(diagnostic.severity);
      result.message = diagnostic.formattedMessage;
      if (diagnostic.location != slang::SourceLocation::NoLocation) {
        result.file = getFileName(diagnostic.location);
        result.line = sourceManager->getLineNumber(diagnostic.location);
        result.column = getColumnNumber(diagnostic.location);
      }
      diagnostics.push_back(std::move(result));
    }

    void reportFallback( // LCOV_EXCL_LINE - compatibility path for unsupported Slang formatters
      const slang::Diagnostic& diagnostic,
      const slang::DiagnosticEngine& engine) {
      SNLSVDiagnostic result; // LCOV_EXCL_LINE
      result.severity = getSeverityString( // LCOV_EXCL_LINE
        engine.getSeverity(diagnostic.code, diagnostic.location)); // LCOV_EXCL_LINE
      result.message = std::string(slang::toString(diagnostic.code)) + ": " + // LCOV_EXCL_LINE
        std::string(engine.getMessage(diagnostic.code)) + // LCOV_EXCL_LINE
        " [diagnostic arguments unavailable]";
      if (diagnostic.location != slang::SourceLocation::NoLocation) { // LCOV_EXCL_LINE
        result.file = getFileName(diagnostic.location); // LCOV_EXCL_LINE
        result.line = sourceManager->getLineNumber(diagnostic.location); // LCOV_EXCL_LINE
        result.column = getColumnNumber(diagnostic.location); // LCOV_EXCL_LINE
      } // LCOV_EXCL_LINE
      diagnostics.push_back(std::move(result)); // LCOV_EXCL_LINE
    }

    std::vector<SNLSVDiagnostic> diagnostics;
};

std::vector<SNLSVDiagnostic> getStructuredDiagnostics(
  const slang::SourceManager& sourceManager,
  const slang::Diagnostics& diagnostics) {
  slang::DiagnosticEngine engine(sourceManager);
  auto client = std::make_shared<StructuredDiagnosticClient>();
  engine.addClient(client);
  for (const auto& diagnostic : diagnostics) {
    try {
      engine.issue(diagnostic);
    } catch (const std::runtime_error& error) {
      if (std::string_view(error.what()) != "No diagnostic formatter for type") { // LCOV_EXCL_LINE
        throw; // LCOV_EXCL_LINE
      }
      client->reportFallback(diagnostic, engine); // LCOV_EXCL_LINE
    }
  }
  return std::move(client->diagnostics);
}

std::string getDiagnosticsReport(
  const slang::SourceManager& sourceManager,
  const slang::Diagnostics& diagnostics) {
  try {
    return slang::DiagnosticEngine::reportAll(sourceManager, diagnostics);
  } catch (const std::runtime_error& error) { // LCOV_EXCL_LINE
    if (std::string_view(error.what()) != "No diagnostic formatter for type") { // LCOV_EXCL_LINE
      throw; // LCOV_EXCL_LINE
    }
    std::ostringstream report; // LCOV_EXCL_LINE
    for (const auto& diagnostic : getStructuredDiagnostics(sourceManager, diagnostics)) { // LCOV_EXCL_LINE
      if (!diagnostic.file.empty()) { // LCOV_EXCL_LINE
        report << diagnostic.file << ":" << diagnostic.line << ":" // LCOV_EXCL_LINE
               << diagnostic.column << ": "; // LCOV_EXCL_LINE
      }
      report << diagnostic.severity << ": " << diagnostic.message << "\n"; // LCOV_EXCL_LINE
    }
    return report.str(); // LCOV_EXCL_LINE
  }
}

struct CompilationFailureDetails {
  std::string reason;
  std::vector<SNLSVDiagnostic> diagnostics;
};

std::optional<CompilationFailureDetails> getCompilationFailureDetails(
  slang::ast::Compilation& compilation,
  bool ignoreUnknownModules = false) {
  const auto& diags = compilation.getAllDiagnostics();
  // Collect only error-level (and above) diagnostics so the failure message
  // is actionable.  Warnings are reported separately via the diagnostics
  // report dump and should not pollute the exception text.
  slang::Diagnostics errors;
  for (const auto& diag : diags) {
    if (not diag.isError()) {
      continue;
    }
    // When blackboxing unknown modules, an unresolved instantiation is expected:
    // slang still reports UnknownModule/UnknownPrimitive, but the constructor
    // materializes an AutoBlackBox for it, so these must not be fatal.
    if (ignoreUnknownModules and
        (diag.code == slang::diag::UnknownModule or
         diag.code == slang::diag::UnknownPrimitive)) { // LCOV_EXCL_LINE
      continue;
    }
    errors.push_back(diag);
  }
  if (errors.empty()) {
    return std::nullopt;
  }

  std::ostringstream reason;
  reason << "SystemVerilog compilation failed";
  if (const auto* sourceManager = compilation.getSourceManager()) {
    const auto details = getDiagnosticsReport(*sourceManager, errors);
    if (!details.empty()) {
      reason << ":\n" << details;
    }
  }
  CompilationFailureDetails failure;
  failure.reason = reason.str();
  if (const auto* sourceManager = compilation.getSourceManager()) {
    failure.diagnostics = getStructuredDiagnostics(*sourceManager, errors);
  }
  return failure;
}

std::optional<CompilationFailureDetails> getDriverFailureDetails(
  const slang::driver::Driver& driver) {
  std::ostringstream details;
  bool hasDetails = false;
  CompilationFailureDetails failure;

  for (const auto& error : driver.sourceLoader.getErrors()) {
    details << error << "\n";
    failure.diagnostics.push_back({"error", {}, 0, 0, error});
    hasDetails = true;
  }

  // LCOV_EXCL_START
  slang::Diagnostics parseDiags;
  for (const auto& tree : driver.syntaxTrees) {
    parseDiags.append_range(tree->diagnostics());
  }
  if (!parseDiags.empty()) {
    parseDiags.sort(driver.sourceManager);
    const auto parseDetails = getDiagnosticsReport(driver.sourceManager, parseDiags);
    if (!parseDetails.empty()) {
      details << parseDetails;
      auto structured = getStructuredDiagnostics(driver.sourceManager, parseDiags);
      failure.diagnostics.insert(
        failure.diagnostics.end(),
        std::make_move_iterator(structured.begin()),
        std::make_move_iterator(structured.end()));
      hasDetails = true;
    }
  }
  // LCOV_EXCL_STOP

  if (!hasDetails) {
    return std::nullopt;
  }

  std::ostringstream reason;
  reason << "SystemVerilog compilation failed:\n" << details.str();
  failure.reason = reason.str();
  return failure;
}

std::string makeUnsupportedCode(const std::string& reason) {
  constexpr std::string_view prefix = "unsupported ";
  if (reason.size() < prefix.size() ||
      !std::equal(
        prefix.begin(), prefix.end(), reason.begin(),
        [](char left, char right) {
          return left == static_cast<char>(std::tolower(static_cast<unsigned char>(right)));
        })) {
    return {}; // LCOV_EXCL_LINE compiler coverage artifact for the fallback return
  }
  std::string normalized;
  bool previousWasSeparator = false;
  for (const unsigned char character : std::string_view(reason).substr(prefix.size())) {
    if (std::isalnum(character)) {
      normalized.push_back(static_cast<char>(std::tolower(character)));
      previousWasSeparator = false;
    } else if (!previousWasSeparator) {
      normalized.push_back('_');
      previousWasSeparator = true;
    }
  }
  while (!normalized.empty() && normalized.back() == '_') {
    normalized.pop_back();
  }
  constexpr std::string_view inferredMemoryPrefix = "inferred_memory_";
  if (std::string_view(normalized).starts_with(inferredMemoryPrefix)) {
    return "sv.unsupported.inferred_memory." + // LCOV_EXCL_LINE compiler coverage artifact
      normalized.substr(inferredMemoryPrefix.size()); // LCOV_EXCL_LINE compiler coverage artifact
  }
  if (std::string_view(normalized).starts_with("procedural_block_") ||
      std::string_view(normalized).starts_with("initial_block_")) {
    return "sv.unsupported.procedural_block";
  }
  return {};
}

bool allNetsArePortNets(SNLDesign* design) {
  for (auto net : design->getBitNets()) {
    if (net->isAssignConstant()) {
      continue;
    }
    if (net->getBitTerms().empty()) {
      return false;
    }
  }
  return true;
}

const Expression* stripConversions(const Expression& expr) {
  const Expression* current = &expr;
  while (current && current->kind == slang::ast::ExpressionKind::Conversion) {
    current = &current->as<slang::ast::ConversionExpression>().operand();
  }
  return current;
}

void collectBinaryOperands(const Expression& expr, slang::ast::BinaryOperator op,
                           std::vector<const Expression*>& operands) {
  const Expression* current = stripConversions(expr);
  if (!current) {
    // LCOV_EXCL_START
    throw SNLSVInternalError(
      "Internal error: null expression while collecting binary operands");
    // LCOV_EXCL_STOP
  }
  if (current->kind == slang::ast::ExpressionKind::BinaryOp) {
    const auto& binaryExpr = current->as<slang::ast::BinaryExpression>();
    if (binaryExpr.op == op) {
      collectBinaryOperands(binaryExpr.left(), op, operands);
      collectBinaryOperands(binaryExpr.right(), op, operands);
      return;
    }
  }
  operands.push_back(current);
}

std::optional<NLDB0::GateType> gateTypeFromBinary(slang::ast::BinaryOperator op) {
  switch (op) {
    case slang::ast::BinaryOperator::BinaryAnd:
    case slang::ast::BinaryOperator::LogicalAnd:
      return NLDB0::GateType(NLDB0::GateType::And);
    case slang::ast::BinaryOperator::BinaryOr:
    case slang::ast::BinaryOperator::LogicalOr:
      return NLDB0::GateType(NLDB0::GateType::Or);
    case slang::ast::BinaryOperator::BinaryXor:
      return NLDB0::GateType(NLDB0::GateType::Xor);
    case slang::ast::BinaryOperator::BinaryXnor:
      return NLDB0::GateType(NLDB0::GateType::Xnor);
    default:
      return std::nullopt;
  }
}

bool isEqualityBinaryOp(slang::ast::BinaryOperator op) {
  switch (op) {
    case slang::ast::BinaryOperator::Equality:
    case slang::ast::BinaryOperator::CaseEquality:
    case slang::ast::BinaryOperator::WildcardEquality:
      return true;
    default:
      return false;
  }
}

bool isInequalityBinaryOp(slang::ast::BinaryOperator op) {
  switch (op) {
    case slang::ast::BinaryOperator::Inequality:
    case slang::ast::BinaryOperator::CaseInequality:
    case slang::ast::BinaryOperator::WildcardInequality:
      return true;
    default:
      return false;
  }
}

bool isCaseComparisonBinaryOp(slang::ast::BinaryOperator op) {
  switch (op) {
    case slang::ast::BinaryOperator::CaseEquality:
    case slang::ast::BinaryOperator::CaseInequality:
    case slang::ast::BinaryOperator::WildcardEquality:
    case slang::ast::BinaryOperator::WildcardInequality:
      return true;
    default:
      return false;
  }
}

bool isRelationalBinaryOp(slang::ast::BinaryOperator op) {
  switch (op) {
    case slang::ast::BinaryOperator::LessThan:
    case slang::ast::BinaryOperator::LessThanEqual:
    case slang::ast::BinaryOperator::GreaterThan:
    case slang::ast::BinaryOperator::GreaterThanEqual:
      return true;
    default:
      return false;
  }
}

bool isKnown2StateConstantExpr(const Expression& expr) {
  const auto* stripped = stripConversions(expr);
  if (!stripped) {
    // LCOV_EXCL_START
    throw SNLSVInternalError(
      "Internal error: null expression in isKnown2StateConstantExpr");
    // LCOV_EXCL_STOP
  }
  const auto* symbol = stripped->getSymbolReference();
  return symbol && symbol->kind == SymbolKind::EnumValue;
}

std::optional<SNLTerm::Direction> toSNLDirection(ArgumentDirection direction) {
  switch (direction) {
    case ArgumentDirection::In:
      return SNLTerm::Direction::Input;
    case ArgumentDirection::Out:
      return SNLTerm::Direction::Output;
    case ArgumentDirection::InOut:
      return SNLTerm::Direction::InOut;
    default:
      return std::nullopt;
  }
}

const char* getPortKindLabel(SymbolKind kind) {
  switch (kind) {
    case SymbolKind::InterfacePort:
      return "interface port";
    case SymbolKind::MultiPort:
      return "multi-port";
    // LCOV_EXCL_START
    default:
      // createTerms only calls this helper for non-Port entries from getPortList.
      return "non-port";
    // LCOV_EXCL_STOP
  }
}

bool tryGetInt64FromSVInt(const slang::SVInt& svInt, int64_t& value) {
  if (svInt.isSigned()) {
    const auto maybeSigned = svInt.as<int64_t>();
    if (!maybeSigned) {
      return false;
    }
    value = *maybeSigned;
    return true;
  }

  const auto maybeUnsigned = svInt.as<uint64_t>();
  if (!maybeUnsigned ||
      *maybeUnsigned > static_cast<uint64_t>(std::numeric_limits<int64_t>::max())) {
    return false;
  }
  value = static_cast<int64_t>(*maybeUnsigned);
  return true;
}

struct UnknownLiteralKinds {
  bool hasX {false};
  bool hasZ {false};

  void add(slang::logic_t bit) {
    hasX = hasX || exactlyEqual(bit, slang::logic_t::x);
    hasZ = hasZ || exactlyEqual(bit, slang::logic_t::z);
  }

  void add(const slang::SVInt& value) {
    for (slang::bitwidth_t index = 0; index < value.getBitWidth(); ++index) {
      add(value[index]);
    }
  }

  std::string label() const {
    if (hasX && hasZ) {
      return "X and Z";
    }
    if (hasZ) {
      return "Z";
    }
    return "X";
  }
};

std::string formatUnknownLiteralWarning(
  std::string_view context,
  const UnknownLiteralKinds& kinds) {
  std::ostringstream message;
  message << kinds.label() << " literal bits in " << context
          << " lowered as 0 in SNL (four-state distinction is not preserved)";
  return message.str();
}

std::optional<std::string> getUnsupportedTypeReason(const Type& type) {
  const auto& canonical = type.getCanonicalType();
  if (canonical.isString()) {
    return "Unsupported SystemVerilog type 'string'";
  }
  if (canonical.isFloating()) {
    return "Unsupported SystemVerilog floating-point type";
  }
  // Keep support conservative but include fixed-size unpacked arrays of representable
  // element types by flattening them to a single SNL bus.
  std::function<std::optional<slang::bitwidth_t>(const Type&)> getRepresentableBitWidth =
    [&](const Type& currentType) -> std::optional<slang::bitwidth_t> {
    const auto& current = currentType.getCanonicalType();
    if (current.isIntegral()) {
      return current.getBitWidth();
    }
    if (!current.isUnpackedArray() || !current.hasFixedRange()) {
      return std::nullopt; // LCOV_EXCL_LINE
    }
    const auto* elementType = current.getArrayElementType();
    if (!elementType) {
      return std::nullopt; // LCOV_EXCL_LINE
    }
    auto elementWidth = getRepresentableBitWidth(*elementType);
    if (!elementWidth) {
      return std::nullopt; // LCOV_EXCL_LINE
    }
    const auto dimensionWidth = static_cast<uint64_t>(current.getFixedRange().width());
    const auto totalWidth = static_cast<uint64_t>(*elementWidth) * dimensionWidth;
    if (totalWidth > std::numeric_limits<slang::bitwidth_t>::max()) {
      return std::nullopt; // LCOV_EXCL_LINE
    }
    return static_cast<slang::bitwidth_t>(totalWidth);
  };

  if (!getRepresentableBitWidth(canonical)) {
    return "Unsupported SystemVerilog type not representable in SNL";
  }
  return std::nullopt;
}

std::optional<slang::ConstantRange> getRangeFromType(const Type& type) {
  const auto& canonical = type.getCanonicalType();

  std::function<std::optional<slang::bitwidth_t>(const Type&)> getRepresentableBitWidth =
    [&](const Type& currentType) -> std::optional<slang::bitwidth_t> {
    const auto& current = currentType.getCanonicalType();
    if (current.isIntegral()) {
      return current.getBitWidth();
    }
    if (!current.isUnpackedArray() || !current.hasFixedRange()) {
      return std::nullopt; // LCOV_EXCL_LINE
    }
    const auto* elementType = current.getArrayElementType();
    if (!elementType) {
      return std::nullopt; // LCOV_EXCL_LINE
    }
    auto elementWidth = getRepresentableBitWidth(*elementType);
    if (!elementWidth) {
      return std::nullopt; // LCOV_EXCL_LINE
    }
    const auto dimensionWidth = static_cast<uint64_t>(current.getFixedRange().width());
    const auto totalWidth = static_cast<uint64_t>(*elementWidth) * dimensionWidth;
    if (totalWidth > std::numeric_limits<slang::bitwidth_t>::max()) {
      return std::nullopt; // LCOV_EXCL_LINE
    }
    return static_cast<slang::bitwidth_t>(totalWidth);
  };

  // Preserve declared packed ranges whenever available.
  if (!canonical.isUnpackedArray() && canonical.hasFixedRange()) {
    const auto fixedRange = canonical.getFixedRange();
    auto totalWidth = getRepresentableBitWidth(canonical);
    if (totalWidth && static_cast<uint64_t>(*totalWidth) == fixedRange.fullWidth()) {
      return fixedRange;
    }
  }

  auto width = getRepresentableBitWidth(canonical);
  if (!width || *width <= 1) {
    return std::nullopt; // LCOV_EXCL_LINE
  }
  const auto maxBit = static_cast<uint64_t>(*width) - 1;
  if (maxBit > static_cast<uint64_t>(std::numeric_limits<int32_t>::max())) {
    return std::nullopt; // LCOV_EXCL_LINE
  }
  return slang::ConstantRange(static_cast<int32_t>(maxBit), 0);
}

SNLNet* getOrCreateNet(SNLDesign* design, const std::string& name, const Type& type) {
  if (auto existing = design->getNet(NLName(name))) {
    return existing;
  }
  auto range = getRangeFromType(type);
  if (range && range->width() > 1) {
    return SNLBusNet::create(design,
      static_cast<NLID::Bit>(range->left),
      static_cast<NLID::Bit>(range->right),
      NLName(name));
  }
  return SNLScalarNet::create(design, NLName(name));
}

#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
double toMilliseconds(std::chrono::nanoseconds duration) {
  return std::chrono::duration<double, std::milli>(duration).count();
}

std::string toSingleLine(const std::string& text) {
  std::string line = text;
  std::replace(line.begin(), line.end(), '\n', ' ');
  std::replace(line.begin(), line.end(), '\r', ' ');
  return line;
}
#endif

