    class SVPerfScopedTimer {
      public:
        SVPerfScopedTimer(SVPerfReport& report, std::chrono::nanoseconds& bucket):
          report_((report.enabled) ? &report : nullptr),
          bucket_((report.enabled) ? &bucket : nullptr) {
          if (report_) {
            start_ = std::chrono::steady_clock::now();
            report_->activeTimers.push_back({bucket_, start_});
          }
        }

        ~SVPerfScopedTimer() {
          if (report_) {
            *bucket_ += std::chrono::steady_clock::now() - start_;
            auto& activeTimers = report_->activeTimers;
            for (auto it = activeTimers.end(); it != activeTimers.begin();) {
              --it;
              if (it->bucket == bucket_ && it->start == start_) {
                activeTimers.erase(it);
                break;
              }
            }
          }
        }

      private:
        SVPerfReport* report_ {nullptr};
        std::chrono::nanoseconds* bucket_ {nullptr};
        std::chrono::steady_clock::time_point start_ {};
    };

    class SVPerfBuildDesignTimer {
      public:
        SVPerfBuildDesignTimer(SVPerfReport& report, std::string modelName):
          report_((report.enabled) ? &report : nullptr),
          modelName_(std::move(modelName)) {
          if (report_) {
            start_ = std::chrono::steady_clock::now();
          }
        }

        ~SVPerfBuildDesignTimer() {
          if (!report_) {
            return;
          }
          const auto elapsed = std::chrono::steady_clock::now() - start_;
          if (elapsed > report_->longestBuildDesignDuration) {
            report_->longestBuildDesignDuration = elapsed;
            report_->longestBuildDesignModel = std::move(modelName_);
          }
        }

      private:
        SVPerfReport* report_ {nullptr};
        std::string modelName_ {};
        std::chrono::steady_clock::time_point start_ {};
    };

    class SVPerfProgressLabelGuard {
      public:
        SVPerfProgressLabelGuard(
          SVPerfReport& report,
          std::string& label,
          std::string value):
          label_((report.enabled) ? &label : nullptr) {
          if (label_) {
            previous_ = *label_;
            *label_ = std::move(value);
          }
        }

        ~SVPerfProgressLabelGuard() {
          if (label_) {
            *label_ = std::move(previous_);
          }
        }

      private:
        std::string* label_ {nullptr};
        std::string previous_ {};
    };

    class SVPerfBuildDesignStackGuard {
      public:
        SVPerfBuildDesignStackGuard(SVPerfReport& report, std::string designName):
          report_((report.enabled) ? &report : nullptr) {
          if (report_) {
            report_->activeBuildDesigns.push_back(std::move(designName));
            report_->maxBuildDesignStackDepth = std::max(
              report_->maxBuildDesignStackDepth,
              report_->activeBuildDesigns.size());
          }
        }

        ~SVPerfBuildDesignStackGuard() {
          if (report_ && !report_->activeBuildDesigns.empty()) {
            report_->activeBuildDesigns.pop_back();
          }
        }

      private:
        SVPerfReport* report_ {nullptr};
    };

    std::chrono::milliseconds getSVPerfSnapshotInterval() const {
      const char* intervalEnv = std::getenv("NAJA_SV_CONSTRUCTOR_REPORT_INTERVAL_MS");
      if (!intervalEnv || !*intervalEnv) {
        return std::chrono::milliseconds(5000);
      }

      char* end = nullptr;
      const auto parsed = std::strtoll(intervalEnv, &end, 10);
      if (end == intervalEnv || *end != '\0' || parsed < 0) {
        return std::chrono::milliseconds(5000);
      }
      return std::chrono::milliseconds(parsed);
    }

    void initializeSVPerfReport(const SNLSVConstructor::Paths& paths) {
      svPerfReport_ = SVPerfReport {};

      std::string reportPath = "sv_constructor_perf.log";
      const char* reportEnv = std::getenv("NAJA_SV_CONSTRUCTOR_REPORT");
      if (reportEnv) {
        std::string overridePath(reportEnv);
        if (!overridePath.empty() && overridePath != "1") {
          reportPath = std::move(overridePath);
        }
      }

      svPerfReport_.enabled = true;
      svPerfReport_.reportPath = reportPath;
      svPerfReport_.constructStart = std::chrono::steady_clock::now();
      svPerfReport_.snapshotInterval = getSVPerfSnapshotInterval();
      svPerfReport_.inputPathCount = paths.size();
    }

    void warnSVPerfReportWriteFailure(const std::string& details) const {
      if (svPerfReport_.writeWarningEmitted) {
        return;
      }
      svPerfReport_.writeWarningEmitted = true;
      NAJA_LOG_WARN("Unable to write SV constructor performance report: {}", details);
    }

    void refreshSVPerfReportSnapshotCounters(
      std::chrono::steady_clock::time_point steadyNow) const {
      svPerfReport_.constructDuration = steadyNow - svPerfReport_.constructStart;
      svPerfReport_.warningCount = warnings_.size();
      svPerfReport_.unsupportedCount = unsupportedElements_.size();
      svPerfReport_.unsupportedWarningCount = unsupportedWarnings_.size();
      if (svPerfReport_.firstWarning.empty() && !warnings_.empty()) {
        svPerfReport_.firstWarning = warnings_.front();
      }
      if (svPerfReport_.firstUnsupported.empty() && !unsupportedElements_.empty()) {
        svPerfReport_.firstUnsupported = unsupportedElements_.front();
      }
      if (svPerfReport_.firstUnsupportedWarning.empty() && !unsupportedWarnings_.empty()) {
        svPerfReport_.firstUnsupportedWarning = unsupportedWarnings_.front();
      }
    }

    void writeSVPerfReportSnapshot(
      bool finalSnapshot,
      std::chrono::steady_clock::time_point steadyNow) const {
      if (!svPerfReport_.enabled || svPerfReport_.snapshotWriteInProgress) {
        return;
      }

      svPerfReport_.snapshotWriteInProgress = true;
      const auto writeGuard = slang::ScopeGuard([&]() {
        svPerfReport_.snapshotWriteInProgress = false;
      });

      refreshSVPerfReportSnapshotCounters(steadyNow);

      const auto durationWithActiveTimers =
        [&](const std::chrono::nanoseconds& bucket) {
        auto duration = bucket;
        for (const auto& activeTimer : svPerfReport_.activeTimers) {
          if (activeTimer.bucket == &bucket) {
            duration += steadyNow - activeTimer.start;
          }
        }
        return duration;
      };
      const auto joinActiveBuildDesigns = [&]() {
        std::ostringstream stack;
        for (size_t i = 0; i < svPerfReport_.activeBuildDesigns.size(); ++i) {
          if (i != 0) {
            stack << " > ";
          }
          stack << toSingleLine(svPerfReport_.activeBuildDesigns[i]);
        }
        return stack.str();
      };

      const auto reportPath = svPerfReport_.reportPath;
      auto tmpPath = reportPath;
      tmpPath += ".tmp";

      std::ofstream output(tmpPath, std::ios::out | std::ios::trunc);
      if (!output) {
        warnSVPerfReportWriteFailure(tmpPath.string());
        return;
      }

      const auto now = std::chrono::system_clock::now();
      const auto nowTime = std::chrono::system_clock::to_time_t(now);
      std::tm localTime {};
#if defined(_WIN32)
      localtime_s(&localTime, &nowTime);
#else
      if (const auto* tm = std::localtime(&nowTime)) {
        localTime = *tm;
      }
#endif

      output << "=== SNLSVConstructor Perf Report "
             << std::put_time(&localTime, "%Y-%m-%d %H:%M:%S") << " ===\n";
      output << "snapshot.kind=" << (finalSnapshot ? "final" : "interim") << "\n";
      output << "snapshot.write_count=" << (svPerfReport_.snapshotWriteCount + 1) << "\n";
      output << "snapshot.interval_ms=" << svPerfReport_.snapshotInterval.count() << "\n";
      output << "snapshot.active_timer_count=" << svPerfReport_.activeTimers.size() << "\n";
      output << "result=";
      if (!finalSnapshot) {
        output << "in_progress\n";
      } else {
        output << (svPerfReport_.success ? "success" : "failure") << "\n";
      }
      if (!svPerfReport_.failureReason.empty()) {
        output << "failure_reason=" << toSingleLine(svPerfReport_.failureReason) << "\n";
      }
      output << "inputs.path_count=" << svPerfReport_.inputPathCount << "\n";
      output << "inputs.top_instance_count=" << svPerfReport_.topInstanceCount << "\n";
      output << "progress.phase="
             << (svPerfReport_.currentPhase.empty() ? "idle" : svPerfReport_.currentPhase)
             << "\n";
      output << "progress.lowering_step="
             << (svPerfReport_.currentLoweringStep.empty()
                  ? "idle"
                  : svPerfReport_.currentLoweringStep)
             << "\n";
      output << "progress.top_instance="
             << (svPerfReport_.currentTopInstance.empty()
                  ? "idle"
                  : toSingleLine(svPerfReport_.currentTopInstance))
             << "\n";
      output << "progress.build_design_current="
             << (svPerfReport_.activeBuildDesigns.empty()
                  ? "idle"
                  : toSingleLine(svPerfReport_.activeBuildDesigns.back()))
             << "\n";
      output << "progress.build_design_stack="
             << (svPerfReport_.activeBuildDesigns.empty()
                  ? "idle"
                  : joinActiveBuildDesigns())
             << "\n";
      output << "progress.build_design_stack_depth="
             << svPerfReport_.activeBuildDesigns.size() << "\n";
      output << "progress.max_build_design_stack_depth="
             << svPerfReport_.maxBuildDesignStackDepth << "\n";
      output << "progress.top_instance_builds_started="
             << svPerfReport_.topInstanceBuildsStarted << "\n";
      output << "progress.top_instance_builds_completed="
             << svPerfReport_.topInstanceBuildsCompleted << "\n";
      output << "progress.build_design_returns=" << svPerfReport_.buildDesignReturns << "\n";
      output << "progress.build_designs_active="
             << (svPerfReport_.buildDesignCalls - svPerfReport_.buildDesignReturns) << "\n";

      output << std::fixed << std::setprecision(3);
      output << "time.construct.total_ms=" << toMilliseconds(svPerfReport_.constructDuration)
             << "\n";
      output << "time.phase.parse_ms="
             << toMilliseconds(durationWithActiveTimers(svPerfReport_.parseDuration)) << "\n";
      output << "time.phase.diagnostics_report_ms="
             << toMilliseconds(
                  durationWithActiveTimers(svPerfReport_.diagnosticsReportDuration)) << "\n";
      output << "time.phase.build_top_designs_ms="
             << toMilliseconds(
                  durationWithActiveTimers(svPerfReport_.buildTopDesignsDuration)) << "\n";
      output << "time.phase.dump_elaborated_ast_ms="
             << toMilliseconds(
                  durationWithActiveTimers(svPerfReport_.elaboratedASTDumpDuration)) << "\n";
      output << "time.phase.unsupported_check_ms="
             << toMilliseconds(
                  durationWithActiveTimers(svPerfReport_.unsupportedCheckDuration)) << "\n";
      output << "time.lowering.build_design_ms="
             << toMilliseconds(durationWithActiveTimers(svPerfReport_.buildDesignDuration))
             << "\n";
      output << "time.lowering.longest_build_design_model_ms="
             << toMilliseconds(svPerfReport_.longestBuildDesignDuration) << "\n";
      output << "time.lowering.create_terms_ms="
             << toMilliseconds(durationWithActiveTimers(svPerfReport_.createTermsDuration))
             << "\n";
      output << "time.lowering.create_nets_ms="
             << toMilliseconds(durationWithActiveTimers(svPerfReport_.createNetsDuration))
             << "\n";
      output << "time.lowering.connect_terms_to_nets_ms="
             << toMilliseconds(
                  durationWithActiveTimers(svPerfReport_.connectTermsToNetsDuration)) << "\n";
      output << "time.lowering.create_continuous_assigns_ms="
             << toMilliseconds(
                  durationWithActiveTimers(svPerfReport_.createContinuousAssignsDuration))
             << "\n";
      output << "time.lowering.create_instances_ms="
             << toMilliseconds(durationWithActiveTimers(svPerfReport_.createInstancesDuration))
             << "\n";
      output << "time.lowering.create_sequential_logic_ms="
             << toMilliseconds(
                  durationWithActiveTimers(svPerfReport_.createSequentialLogicDuration))
             << "\n";
      output << "time.lowering.annotate_source_info_ms="
             << toMilliseconds(
                  durationWithActiveTimers(svPerfReport_.annotateSourceInfoDuration))
             << "\n";
      output << "time.lowering.clone_rtl_infos_ms="
             << toMilliseconds(durationWithActiveTimers(svPerfReport_.cloneRTLInfosDuration))
             << "\n";

      output << "count.design.build_calls=" << svPerfReport_.buildDesignCalls << "\n";
      output << "count.design.build_cache_hits=" << svPerfReport_.buildDesignCacheHits << "\n";
      output << "count.design.unique_built="
             << (svPerfReport_.buildDesignCalls - svPerfReport_.buildDesignCacheHits) << "\n";
      output << "count.design.longest_build_design_model="
             << (svPerfReport_.longestBuildDesignModel.empty()
                  ? "none"
                  : toSingleLine(svPerfReport_.longestBuildDesignModel))
             << "\n";
      output << "count.lowering.create_terms_calls=" << svPerfReport_.createTermsCalls << "\n";
      output << "count.lowering.create_nets_calls=" << svPerfReport_.createNetsCalls << "\n";
      output << "count.lowering.connect_terms_to_nets_calls="
             << svPerfReport_.connectTermsToNetsCalls << "\n";
      output << "count.lowering.create_continuous_assigns_calls="
             << svPerfReport_.createContinuousAssignsCalls << "\n";
      output << "count.lowering.create_instances_calls="
             << svPerfReport_.createInstancesCalls << "\n";
      output << "count.lowering.create_sequential_logic_calls="
             << svPerfReport_.createSequentialLogicCalls << "\n";
      output << "count.lowering.annotate_source_info_calls="
             << svPerfReport_.annotateSourceInfoCalls << "\n";
      output << "count.rtl_info.create_design_calls="
             << svPerfReport_.rtlInfoCreateDesignCalls << "\n";
      output << "count.rtl_info.create_design_object_calls="
             << svPerfReport_.rtlInfoCreateDesignObjectCalls << "\n";
      output << "count.rtl_info.set_calls=" << svPerfReport_.rtlInfoSetCalls << "\n";
      output << "count.rtl_info.clone_calls=" << svPerfReport_.rtlInfoCloneCalls << "\n";
      output << "count.rtl_info.cloned_entries="
             << svPerfReport_.rtlInfoClonedEntries << "\n";
      output << "count.symbol.port_visited=" << svPerfReport_.portSymbolsVisited << "\n";
      output << "count.symbol.port_created=" << svPerfReport_.portsCreated << "\n";
      output << "count.symbol.net_or_variable_visited="
             << svPerfReport_.netOrVariableSymbolsVisited << "\n";
      output << "count.symbol.net_created=" << svPerfReport_.netsCreated << "\n";
      output << "count.symbol.continuous_assign_visited="
             << svPerfReport_.continuousAssignsVisited << "\n";
      output << "count.symbol.instance_visited=" << svPerfReport_.instanceSymbolsVisited << "\n";
      output << "count.symbol.instance_created=" << svPerfReport_.instancesCreated << "\n";
      output << "count.symbol.procedural_block_visited="
             << svPerfReport_.proceduralBlocksVisited << "\n";
      output << "count.block.always_comb_visited="
             << svPerfReport_.alwaysCombBlocksVisited << "\n";
      output << "count.block.always_comb_lowered="
             << svPerfReport_.alwaysCombBlocksLowered << "\n";
      output << "count.block.sequential_visited="
             << svPerfReport_.sequentialBlocksVisited << "\n";
      output << "count.block.sequential_lowered="
             << svPerfReport_.sequentialBlocksLowered << "\n";
      output << "count.warning=" << svPerfReport_.warningCount << "\n";
      // Keep count.unsupported as the compatibility alias for failure-causing
      // unsupported errors. Unsupported warnings never make this count nonzero.
      output << "count.unsupported=" << svPerfReport_.unsupportedCount << "\n";
      output << "count.unsupported_error=" << svPerfReport_.unsupportedCount << "\n";
      output << "count.unsupported_warning="
             << svPerfReport_.unsupportedWarningCount << "\n";

      if (!svPerfReport_.firstWarning.empty()) {
        output << "first_warning=" << toSingleLine(svPerfReport_.firstWarning) << "\n";
      }
      if (!svPerfReport_.firstUnsupported.empty()) {
        output << "first_unsupported=" << toSingleLine(svPerfReport_.firstUnsupported) << "\n";
        output << "first_unsupported_error="
               << toSingleLine(svPerfReport_.firstUnsupported) << "\n";
      }
      if (!svPerfReport_.firstUnsupportedWarning.empty()) {
        output << "first_unsupported_warning="
               << toSingleLine(svPerfReport_.firstUnsupportedWarning) << "\n";
      }
      output << "\n";
      output.close();
      if (!output.good()) {
        warnSVPerfReportWriteFailure(tmpPath.string());
        return;
      }

      std::error_code renameError;
      std::filesystem::rename(tmpPath, reportPath, renameError);
      if (renameError) {
        std::error_code removeError;
        std::filesystem::remove(reportPath, removeError);
        renameError.clear();
        std::filesystem::rename(tmpPath, reportPath, renameError);
      }
      if (renameError) {
        warnSVPerfReportWriteFailure(renameError.message());
        std::error_code removeError;
        std::filesystem::remove(tmpPath, removeError);
        return;
      }

      svPerfReport_.lastSnapshotWrite = steadyNow;
      ++svPerfReport_.snapshotWriteCount;
    }

    void maybeWriteSVPerfReportSnapshot(bool force = false) const {
      if (!svPerfReport_.enabled || svPerfReport_.snapshotInterval.count() == 0) {
        return;
      }
      const auto steadyNow = std::chrono::steady_clock::now();
      if (!force &&
          svPerfReport_.lastSnapshotWrite.time_since_epoch().count() != 0 &&
          steadyNow - svPerfReport_.lastSnapshotWrite < svPerfReport_.snapshotInterval) {
        return;
      }
      writeSVPerfReportSnapshot(false, steadyNow);
    }

    void noteSVPerfProgress() const {
      if (!svPerfReport_.enabled || svPerfReport_.snapshotInterval.count() == 0) {
        return;
      }
      if ((++svPerfReport_.progressEventsSinceSnapshotCheck & 0x3ff) != 0) {
        return;
      }
      maybeWriteSVPerfReportSnapshot();
    }

    void finalizeSVPerfReport() const {
      if (!svPerfReport_.enabled) {
        return;
      }

      writeSVPerfReportSnapshot(true, std::chrono::steady_clock::now());
    }
#endif

    void construct(const SNLSVConstructor::Paths& paths) {
      if (!library_) {
        throw SNLSVInternalError("SNLSVConstructor requires a valid NLLibrary");
      }
      SNLSVLiveASTLinkRegistry::clear(library_->getDB());
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
      initializeSVPerfReport(paths);
      const auto perfReportGuard = slang::ScopeGuard([&]() {
        finalizeSVPerfReport();
      });
#endif

      driver_.reset();
      syntaxTrees_.clear();
      warnings_.clear();
      emittedWarnings_.clear();
      loggedWarningCodes_.clear();
      unsupportedElements_.clear();
      unsupportedElementDetails_.clear();
      unsupportedWarnings_.clear();
      emittedUnsupportedWarnings_.clear();
      reportSections_.clear();
      slangSeverityCounts_.clear();
      slangDiagnosticCount_ = 0;
      elaborationWarningCount_ = 0;
      unsupportedWarningCount_ = 0;
      unsupportedErrorCount_ = 0;
      elaborationWarningCodes_.clear();
      unsupportedWarningCodes_.clear();
      unsupportedErrorCodes_.clear();
      warningPolicyNoticeEmitted_ = false;
      diagnosticsReportFinalized_ = false;
      warnedUninferredMemorySymbols_.clear();
      handledInitialBlocks_.clear();
      loweredNetInitializers_.clear();
      loweredVariableInitializers_.clear();
      dynamicElementSelectCache_.clear();
      gateOutputCache_.clear();
      initializeDiagnosticsReport();
      const auto diagnosticsReportGuard = slang::ScopeGuard([&]() {
        if (!diagnosticsReportFinalized_) {
          try {
            finalizeDiagnosticsReport(false, "unknown non-std exception");
          } catch (...) {
          }
        }
      });
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
      maybeWriteSVPerfReportSnapshot(true);
#endif
      try {
        {
          NajaPerf::Scope scope("SNLSVConstructorImpl::constructWithSlangDriver");
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
          const SVPerfProgressLabelGuard progress(
            svPerfReport_,
            svPerfReport_.currentPhase,
            "parse");
          const SVPerfScopedTimer timer(svPerfReport_, svPerfReport_.parseDuration);
#endif
          constructWithSlangDriver(paths);
        }
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
        maybeWriteSVPerfReportSnapshot();
#endif

        if (const auto* sourceManager = compilation_->getSourceManager()) {
          recordSlangDiagnostics(getStructuredDiagnostics(
            *sourceManager, compilation_->getAllDiagnostics()));
        }
        if (auto failure = getCompilationFailureDetails(
              *compilation_, options_.blackboxUnknownModules)) {
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
          const SVPerfProgressLabelGuard progress(
            svPerfReport_,
            svPerfReport_.currentPhase,
            "diagnostics_report");
          const SVPerfScopedTimer timer(
            svPerfReport_,
            svPerfReport_.diagnosticsReportDuration);
#endif
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
          if (svPerfReport_.failureReason.empty()) {
            svPerfReport_.failureReason = failure->reason;
          }
#endif
          throw SNLSVSyntaxError(failure->reason, std::move(failure->diagnostics));
        }

        const auto& root = compilation_->getRoot();
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
        svPerfReport_.topInstanceCount = root.topInstances.size();
#endif
        {
          NajaPerf::Scope scope("SNLSVConstructorImpl::buildTopDesigns");
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
          const SVPerfProgressLabelGuard progress(
            svPerfReport_,
            svPerfReport_.currentPhase,
            "build_top_designs");
          const SVPerfScopedTimer timer(
            svPerfReport_,
            svPerfReport_.buildTopDesignsDuration);
#endif
          for (const auto* top : root.topInstances) {
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
            const SVPerfProgressLabelGuard topProgress(
              svPerfReport_,
              svPerfReport_.currentTopInstance,
              std::string(top->body.getDefinition().name));
            ++svPerfReport_.topInstanceBuildsStarted;
            noteSVPerfProgress();
#endif
            buildDesign(top->body);
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
            ++svPerfReport_.topInstanceBuildsCompleted;
            maybeWriteSVPerfReportSnapshot();
#endif
          }
        }
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
        maybeWriteSVPerfReportSnapshot();
#endif

        {
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
          const SVPerfProgressLabelGuard progress(
            svPerfReport_,
            svPerfReport_.currentPhase,
            "dump_elaborated_ast");
          const SVPerfScopedTimer timer(
            svPerfReport_,
            svPerfReport_.elaboratedASTDumpDuration);
#endif
          dumpElaboratedASTJson(root);
        }
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
        maybeWriteSVPerfReportSnapshot();
#endif

        {
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
          const SVPerfProgressLabelGuard progress(
            svPerfReport_,
            svPerfReport_.currentPhase,
            "diagnostics_report");
          const SVPerfScopedTimer timer(
            svPerfReport_,
            svPerfReport_.diagnosticsReportDuration);
#endif
        }
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
        maybeWriteSVPerfReportSnapshot();
#endif

        {
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
          const SVPerfProgressLabelGuard progress(
            svPerfReport_,
            svPerfReport_.currentPhase,
            "unsupported_check");
          const SVPerfScopedTimer timer(
            svPerfReport_,
            svPerfReport_.unsupportedCheckDuration);
#endif
          throwIfUnsupportedElements();
        }
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
        maybeWriteSVPerfReportSnapshot();
#endif
        persistLiveASTLink();
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
        svPerfReport_.success = true;
#endif
        finalizeDiagnosticsReport(true, {});
      } catch (const std::exception& e) {
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
        if (svPerfReport_.failureReason.empty()) {
          svPerfReport_.failureReason = e.what();
        }
#endif
        if (!diagnosticsReportFinalized_) {
          finalizeDiagnosticsReport(false, e.what());
        }
        throw;
      } catch (...) { // LCOV_EXCL_LINE
#ifdef NAJA_ENABLE_SV_CONSTRUCTOR_PERF_REPORT
        if (svPerfReport_.failureReason.empty()) {
          svPerfReport_.failureReason = "unknown non-std exception";
        }
#endif
        if (!diagnosticsReportFinalized_) { // LCOV_EXCL_LINE
          finalizeDiagnosticsReport(false, "unknown non-std exception"); // LCOV_EXCL_LINE
        } // LCOV_EXCL_LINE
        throw; // LCOV_EXCL_LINE
      }
    }

