        const auto& valueRangeExpr = strippedItemExpr->as<slang::ast::ValueRangeExpression>();
        if (valueRangeExpr.rangeKind != slang::ast::ValueRangeKind::Simple) {
          return false; // LCOV_EXCL_LINE
        }

